object AWSServiceExample {
  def main(args: Array[String]): Unit = {
    val region = Region.US_EAST_1
    
    val service = new AWSServiceClient(DefaultCredentials, region)
    
    service.listS3Buckets() match {
      case Success(buckets) => 
        println(s"S3 Buckets: ${buckets.mkString(", ")}")
      case Failure(exception) => 
        println(s"Error listing buckets: ${exception.getMessage}")
    }
    
    val tableName = "MyTable"
    val item = Map(
      "id" -> AttributeValue.builder().s("123").build(),
      "name" -> AttributeValue.builder().s("John Doe").build()
    )
    
    service.putItemDynamoDB(tableName, item) match {
      case Success(_) => println("Item added to DynamoDB")
      case Failure(exception) => println(s"Error adding item: ${exception.getMessage}")
    }
    
    service.close()
  }
}